INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 2, 27, 100101, 155, "トゥインクルウィッシュ", "A", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "人助けが大好き！　前向き格闘娘", "獣人族", 0, "人助け、応援", 44, "ヒヨリ", "東山奈央", 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 2, 5, 100201, 158, "トゥインクルウィッシュ", "O", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "戦闘のサポートが得意な、心優しい少女", "ヒューマン", 0, "料理、人間観察", 47, "ユイ", "種田梨沙", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 2, 12, 100301, 163, "トゥインクルウィッシュ", "B", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "クールで何事にも真っ直ぐな剣士", "魔族", 0, "読書、乗馬、お茶", 46, "レイ", "早見沙織", 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 5, 10, 100401, 128, "リトルリリカル", "O", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", "探検好きのイタズラっ子", "ヒューマン", 0, "いたずら、探検", 27, "ミソギ", "諸星すみれ", 9);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 8, 25, 100501, 146, "王宮騎士団（NIGHTMARE）", "O", "？？？", "ヒーローに憧れる騎士見習いの少女", "獣人族", 0, "ヒーローごっこ", 40, "マツリ", "下田麻美", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 7, 22, 100601, 150, "悪魔偽王国軍（ディアボロス）", "O", "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "甘え上手なみんなの人気者", "魔族", 0, "サックス", 42, "アカリ", "浅倉杏美", 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 7, 23, 100701, 130, "悪魔偽王国軍（ディアボロス）", "B", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "プリン大好きゴースト娘", "魔族", 0, "プリンを食べること", 32, "ミヤコ", "雨宮天", 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 15, 10, 100801, 150, "ヴァイスフリューゲル　ランドソル支部", "AB", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "ボクは誰よりも美しい", "エルフ", 0, "鏡で自分を見ること", 40, "ユキ", "大空直美", 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 13, 5, 100901, 159, "トワイライトキャラバン", "A", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "前世を信じる中二病患者、「疾風の冥姫」", "魔族", 0, "小説執筆", 45, "アンナ", "髙野麻美", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 10, 22, 101001, 155, "自警団（カォン）", "O", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "マホマホ王国のプリンセス", "獣人族", 0, "空想、ぬいぐるみ集め", 42, "マホ", "内田真礼", 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 3, 25, 101101, 156, "ラビリンス", "A", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "人懐っこくてマシンガントークな妹系少女", "ヒューマン", 0, "お裁縫", 44, "リノ", "阿澄佳奈", 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 6, 24, 101201, 156, "フォレスティエ", "A", "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "みんなのために超能力を使う眠り姫", "エルフ", 0, "妹と遊ぶこと、二度寝、昼寝、早寝", 46, "ハツネ", "大橋彩香", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 13, 21, 101301, 166, "トワイライトキャラバン", "O", "", "オタク全開な魔法少女", "魔族", 0, "読書、魔法", 55, "ナナカ", "佳村はるか", 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 10, 3, 101401, 152, "自警団（カォン）", "AB", "test", "頭脳明晰な美少女名探偵", "獣人族", 0, "読書、推理", 41, "カスミ", "水瀬いのり", 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 6, 5, 101501, 165, "フォレスティエ", "O", "test", "母性溢れる優しいみんなの「ミサト先生」", "エルフ", 0, "絵本作り", 54, "ミサト", "國府田マリ子", 21);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 14, 10, 101601, 167, "ルーセント学院", "O", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "天真爛漫で人気者のカリスマモデル", "魔族", 0, "ファッション", 48, "スズナ", "上坂すみれ", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 10, 7, 101701, 158, "自警団（カォン）", "A", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "いつでも「なんくるないさ～」な天然娘", "獣人族", 0, "踊り、空手", 53, "カオリ", "高森奈津美", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 14, 14, 101801, 162, "ルーセント学院", "B", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", "多くの男性を魅了する無垢な女教師", "魔族", 0, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 52, "イオ", "伊藤静", 23);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 5, 3, 102001, 117, "リトルリリカル", "O", "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "お歌もにんじんも、ウサギさんも大好き♪", "獣人族", 0, "かわいいもの集め", 21, "ミミ", "日高里菜", 10);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 9, 9, 102101, 150, "サレンディア救護院", "B", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "泣き虫で臆病な守ってあげたい女の子", "ヒューマン", 0, "観劇、おままごと", 40, "クルミ", "植田佳奈", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 7, 22, 102201, 150, "悪魔偽王国軍（ディアボロス）", "O", "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "人見知りであまのじゃくな女の子", "魔族", 0, "ゲーム全般", 40, "ヨリ", "原紗友里", 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, 9, 10, 102301, 148, "サレンディア救護院", "B", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "ぷうきちといつも一緒！", "ヒューマン", 0, "屋内でできる遊び", 38, "アヤネ", "芹澤優", 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 9, 12, 102501, 154, "サレンディア救護院", "O", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "お嬢さまのためにがんばるドジっ娘メイド", "ヒューマン", 0, "ご奉仕", 43, "スズメ", "悠木碧", 15);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 11, 1, 102601, 144, "牧場（エリザベスパーク）", "B", "test", "遊びと睡眠が何より大事なぐうたら娘", "獣人族", 0, "あんパン", 42, "リン", "小岩井ことり", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 13, 30, 102701, 154, "トワイライトキャラバン", "B", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "運命の相手に一途すぎる乙女", "魔族", 0, "実験、裁縫、料理", 43, "エリコ", "橋本ちなみ", 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 9, 4, 102801, 156, "サレンディア救護院", "A", "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "救護院を経営する優しい庶民派お嬢様", "エルフ", 0, "経営、お茶会", 43, "サレン", "堀江由衣", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 4, 24, 102901, 157, "カルミナ", "B", "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", "歌って踊れる大人気アイドル", "ヒューマン", 0, "舞台鑑賞、ダンス", 40, "ノゾミ", "日笠陽子", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 15, 31, 103001, 163, "ヴァイスフリューゲル　ランドソル支部", "O", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "トーゴクの神秘、オシエテクダサイ！", "ヒューマン", 0, "忍法開発", 51, "ニノン", "佐藤聡美", 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 7, 22, 103101, 157, "悪魔偽王国軍（ディアボロス）", "AB", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "占いが得意な霊能少女", "魔族", 0, "占い", 42, "シノブ", "大坪由佳", 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 12, 12, 103201, 157, "メルクリウス財団", "AB", "この私とともにいる限り、\nお金に不自由はさせませんわ！", "一人前の商人を目指すパワフルお嬢様", "ヒューマン", 0, "慈善事業", 45, "アキノ", "松嵜麗", 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 11, 3, 103301, 142, "牧場（エリザベスパーク）", "B", "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "みんなを笑顔にするお笑い牧場主", "ヒューマン", 0, "漫才", 35, "マヒル", "新田恵海", 20);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 12, 16, 103401, 164, "メルクリウス財団", "A", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "純情でほっとけない大人の女性", "エルフ", 0, "ウインドーショッピング", 55, "ユカリ", "今井麻美", 22);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, 5, 2, 103601, 118, "リトルリリカル", "A", "test", "礼儀正しくしっかり者のちびっ子優等生", "エルフ", 0, "お勉強", 21, "キョウカ", "小倉唯", 8);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 8, 11, 103701, 149, "王宮騎士団（NIGHTMARE）", "A", "test", "義理堅くてからかい好きな剣術少女", "ヒューマン", 0, "剣術、年長者をからかう", 43, "トモ", "茅原実里", 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 11, 3, 103801, 153, "牧場（エリザベスパーク）", "A", "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "読書が趣味の病弱少女", "獣人族", 0, "読書、お散歩", 40, "シオリ", "小清水亜美", 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 6, 6, 104001, 158, "フォレスティエ", "AB", "友達ができるその日まで…\nBB団で\nトレーニングですっ！", "「友達」に憧れる、エルフの森の女の子", "エルフ", 0, "友達作りのイメトレ", 44, "アオイ", "花澤香菜", 13);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 4, 3, 104201, 163, "カルミナ", "O", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "人々を守るために歌う、唱喚士の少女", "ヒューマン", 0, "各種楽器", 46, "チカ", "福原綾香", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 10, 9, 104301, 168, "自警団（カォン）", "O", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", "男勝りで情に厚いワイルド娘", "獣人族", 0, "お菓子作り", 54, "マコト", "小松未可子", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, 7, 5, 104401, 172, "悪魔偽王国軍（ディアボロス）", "A", "test", "かつては夜を支配した最強の吸血鬼", "魔族", 0, "世界征服", 50, "イリヤ", "丹下桜", "??");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 15, 19, 104501, 157, "ヴァイスフリューゲル　ランドソル支部", "AB", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "妄想大好き！　ほんとは照れ屋な女の子", "ヒューマン", 0, "小説を読むこと", 49, "クウカ", "長妻樹里", 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 12, 1, 104601, 158, "メルクリウス財団", "AB", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "弱きを助け強きをくじく猫娘", "獣人族", 0, "猫とたわむれること", 48, "タマキ", "沼倉愛美", 19);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 8, 25, 104701, 171, "王宮騎士団（NIGHTMARE）", "A", "？？？", "素顔を見せない冷静沈着な女性騎士", "ヒューマン", 0, "格闘技、湯浴み", 50, "ジュン", "川澄綾子", 25);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 12, 11, 104801, 163, "メルクリウス財団", "O", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "仕事も私事も効率優先な傭兵少女", "ヒューマン", 0, "傭兵などのアルバイト", 49, "ミフユ", "田所あずさ", 20);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 3, 24, 104901, 168, "ラビリンス", "O", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "お姉ちゃんがお世話してあげるからねっ！", "ヒューマン", 0, "家事全般", 54, "シズル", "生天目仁美", 18);
