INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 13, 7, 105101, 166, "トワイライトキャラバン", "A", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "実験が趣味の危険な科学者", "ヒューマン", 0, "研究、実験", 53, "ミツキ", "三石琴乃", 27);
