INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, 12, 1, 107901, 158, "メルクリウス財団", "AB", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "弱きを助け強きをくじく猫娘", "獣人族", 0, "猫とたわむれること", 48, "タマキ（サマー）", "沼倉愛美", 19);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 12, 11, 108001, 163, "メルクリウス財団", "O", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "仕事も私事も効率優先な傭兵少女", "ヒューマン", 0, "傭兵などのアルバイト", 49, "ミフユ（サマー）", "田所あずさ", 20);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 7, 22, 108101, 157, "悪魔偽王国軍（ディアボロス）", "AB", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "占いが得意な霊能少女", "魔族", 0, "占い", 42, "シノブ（ハロウィン）", "大坪由佳", 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 7, 23, 108201, 130, "悪魔偽王国軍（ディアボロス）", "B", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "プリン大好きゴースト娘", "魔族", 0, "プリンを食べること", 32, "ミヤコ（ハロウィン）", "雨宮天", 14);
