INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 4, 3, 108401, 163, "カルミナ", "O", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "人々を守るために歌う、唱喚士の少女", "ヒューマン", 0, "各種楽器", 46, "チカ（クリスマス）", "福原綾香", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, 9, 9, 108501, 150, "サレンディア救護院", "B", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "泣き虫で臆病な守ってあげたい女の子", "ヒューマン", 0, "観劇、おままごと", 40, "クルミ（クリスマス）", "植田佳奈", 12);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, 9, 10, 108601, 148, "サレンディア救護院", "B", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "ぷうきちといつも一緒！", "ヒューマン", 0, "屋内でできる遊び", 38, "アヤネ（クリスマス）", "芹澤優", 14);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 2, 27, 108701, 155, "トゥインクルウィッシュ", "A", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "人助けが大好き！　前向き格闘娘", "獣人族", 0, "人助け、応援", 44, "ヒヨリ（ニューイヤー）", "東山奈央", 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, 2, 5, 108801, 158, "トゥインクルウィッシュ", "O", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "戦闘のサポートが得意な、心優しい少女", "ヒューマン", 0, "料理、人間観察", 47, "ユイ（ニューイヤー）", "種田梨沙", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, 2, 12, 108901, 163, "トゥインクルウィッシュ", "B", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "クールで何事にも真っ直ぐな剣士", "魔族", 0, "読書、乗馬、お茶", 46, "レイ（ニューイヤー）", "早見沙織", 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, 13, 30, 109001, 154, "トワイライトキャラバン", "B", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "運命の相手に一途すぎる乙女", "魔族", 0, "実験、裁縫、料理", 43, "エリコ（バレンタイン）", "橋本ちなみ", 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 3, 24, 109101, 168, "ラビリンス", "O", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "お姉ちゃんがお世話してあげるからねっ！", "ヒューマン", 0, "家事全般", 54, "シズル（バレンタイン）", "生天目仁美", 18);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "", 1, 109201, 156, "？？？", "AB", "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", "英霊と契約を結んだマナリアの天才王女", "ヒューマン", 0, "読書", 55, "アン", "日笠陽子", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, "", 4, 109301, 144, "？？？", "O", "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", "マナリア魔法学院の新入生", "ヒューマン", 0, "食べること、眠ること", 45, "ルゥ", "こやまきみこ", 16);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "", 3, 109401, 167, "？？？", "B", "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", "人を超越した力を有す心優しい竜姫", "半人半竜", 0, "ピアノ", 67, "グレア", "福原綾香", 17);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 15, 19, 109501, 157, "ヴァイスフリューゲル　ランドソル支部", "AB", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "妄想大好き！　ほんとは照れ屋な女の子", "ヒューマン", 0, "小説を読むこと", 49, "クウカ（オーエド）", "長妻樹里", 18);
